examples.toCode:
package main
import "encoding/json"

type User struct {
	Name string `json:"name"`
}

func parseUser(jsonStr string) (string, error) {
	var u User
	err := json.Unmarshal([]byte(jsonStr), &u)
	if err != nil {
		return "", err
	}
	return "User: " + u.Name, nil
}
